export const theme = {
  colors: {
    primary: '#1a73e8',
    secondary: '#34a853',
    background: '#f5f7fa',
    card: '#ffffff',
    text: '#202124',
    textSecondary: '#5f6368',
    success: '#34a853',
    warning: '#fbbc05',
    danger: '#ea4335',
    info: '#4285f4',
    border: '#dadce0',
  },
  spacing: {
    xs: 4,
    sm: 8,
    md: 16,
    lg: 24,
    xl: 32,
  },
  typography: {
    h1: {
      fontSize: 28,
      fontWeight: 'bold',
    },
    h2: {
      fontSize: 22,
      fontWeight: 'bold',
    },
    h3: {
      fontSize: 18,
      fontWeight: '600',
    },
    body: {
      fontSize: 16,
    },
    caption: {
      fontSize: 14,
      color: '#5f6368',
    },
  },
  borderRadius: {
    sm: 8,
    md: 12,
    lg: 16,
  },
};
